async function decodeSrcDocGzip(): Promise<string> {
  const binary = atob(SRC_DOC_GZIP_BASE64);
  const bytes = new Uint8Array(binary.length);

  for (let i = 0; i < binary.length; i += 1) {
    bytes[i] = binary.charCodeAt(i);
  }

  if (typeof DecompressionStream === "undefined") {
    throw new Error("This browser does not support DecompressionStream.");
  }

  const decompressedStream = new Blob([bytes]).stream().pipeThrough(new DecompressionStream("gzip"));
  return await new Response(decompressedStream).text();
}

type DeltaReviewTabletComponentProps = {
  height?: number;
};

function resolveHeight(value: number | undefined, fallback: number, min: number): number {
  if (typeof value !== "number" || !Number.isFinite(value) || value <= 1) return fallback;
  return Math.max(min, value);
}

export default function DeltaReviewTabletComponent(props: DeltaReviewTabletComponentProps) {
  const height = resolveHeight(props.height, 820, 420);
  const [srcDoc, setSrcDoc] = React.useState("");
  const [loadError, setLoadError] = React.useState("");

  React.useEffect(() => {
    let cancelled = false;

    void decodeSrcDocGzip()
      .then((doc) => {
        if (cancelled) return;
        setSrcDoc(doc);
      })
      .catch((error) => {
        if (cancelled) return;
        setLoadError(error instanceof Error ? error.message : "Unable to load component.");
      });

    return () => {
      cancelled = true;
    };
  }, []);

  return (
    <div
      style={{
        width: "100%",
        height,
        minHeight: 420,
        overflow: "hidden",
        background: "#f6f5f2",
      }}
    >
      {srcDoc ? (
        <iframe
          title="Patricius Delta Review Tablet"
          srcDoc={srcDoc}
          style={{
            display: "block",
            width: "100%",
            height: "100%",
            border: "0",
            background: "#f6f5f2",
          }}
        />
      ) : (
        <div
          style={{
            width: "100%",
            height: "100%",
            display: "grid",
            placeItems: "center",
            color: "#6b7280",
            fontFamily: "-apple-system, BlinkMacSystemFont, 'Segoe UI', Inter, 'Helvetica Neue', Arial, sans-serif",
            fontSize: 13,
            padding: 16,
            textAlign: "center",
          }}
        >
          {loadError || "Loading Patricius review..."}
        </div>
      )}
    </div>
  );
}

DeltaReviewTabletComponent.defaultProps = {
  height: 820,
};
